var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에블린 언니, 오늘 진짜 잘 놀았어요.","JPN":"エヴリン姉さん、今日は本当に楽しかったです。","ENG":"Evelyn, I had such fun today.","TWN":"伊芙琳姊姊，今天真的玩得好開心喔。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"놀이 공원 진짜 오랜만이거든요. 어렸을 때 한 번 왔던 거 빼고 처음이에요.","JPN":"遊園地、本当に久しぶりだったんです。小さい頃一度来たきりだったので。","ENG":"It’s been so long since I last visited an amusement park. I only went once when I was a child.","TWN":"好久沒來遊樂園了，我只有小時候來過一次，後來就沒來過了。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"쳇, 조금만 더 시간이 있었으면 귀신의 집에 있는 귀신들을 다 쓰러트릴 수 있었는데.","JPN":"ちえっ、もう少し時間があればお化け屋敷のやつら全員やっつけられたのに。","ENG":"Darn, I could have defeated all the ghosts in the haunted house if I had more time.","TWN":"嘖，時間不夠啦，我都還沒打倒那些鬼屋裡的鬼欸！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"…아얏!!","JPN":"……痛っ！","ENG":"Ow!","TWN":"…可惜！！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 멍청아!","JPN":"このバカ！","ENG":"You idiot!","TWN":"你這個傻瓜！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"남의 장사 거덜 낼 일 있어? 귀신의 집에서 일하는 귀신을 때리면 하면 어떡해?","JPN":"人に迷惑ばかりかけて！　お化け屋敷で働く人を殴ってどうする！","ENG":"You almost ruined their business! Why did you hit them?","TWN":"幹嘛妨礙人家做生意？沒事打鬼屋裡的工讀生幹嘛？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나, 나는 진짜 귀신인 줄 알았다니깐!","JPN":"わ、私は本物のお化けかと思っただけなの！","ENG":"I-I thought they were real ghosts!","TWN":"我…我還以為他們是真的鬼嘛！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗, 다들 즐거워 보여서 다행이네.","JPN":"ふふっ。みんな楽しんでくれたようでよかったわ。","ENG":"Haha, I’m glad to see you’re all enjoying yourselves.","TWN":"呵呵，大家玩得開心就好。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"근데 에블린 언니, 놀이 공원 티켓은 어떻게 공짜로 얻은 거예요? 그것도 네 장씩이나.","JPN":"ところでエヴリン姉さん、遊園地のチケットをタダで貰ったって、どうしたんですか？\\nしかも4枚も。","ENG":"By the way, Evelyn, where did you get all the free tickets?","TWN":"不過伊芙琳姊姊，為什麼你會有免費的門票，而且還四張欸？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아하, 이거?","JPN":"ああ、これね。","ENG":"Oh, these?","TWN":"哈哈，你說這個嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"사실 원래 티켓을 얻게 된 건 몇 개월 전이야.","JPN":"実はチケットをもらったのは、数ヶ月も前のことなんだけど。","ENG":"I actually bought a ticket a few months ago.","TWN":"其實我在幾個月前就拿到門票了。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"갑작스러운 대규모 침식 재난으로 놀이 공원이 문을 닫는 바람에 못 쓰게 됐지, 뭐야?","JPN":"突然の大規模侵食災害で遊園地が閉鎖しちゃって、有効期限が切れてしまったの。","ENG":"But then a large-scale Corruption disaster happened, so the amusement park had to close for a while.","TWN":"只是突然發生大規模侵蝕災難，導致遊樂園暫停營業，所以也沒辦法來。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그런데 이번에 다시 개장하면서 사과의 의미로 공짜 티켓을 네 장이나 받게 된 거지.","JPN":"だけど営業再開することになって、お詫びとしてチケットを4枚もらえたのよ。","ENG":"When they reopened, they gave me four free tickets as compensation.","TWN":"遊樂園想這次趁著改裝順便補償之前沒能用到門票的客人，所以我就獲得四張囉。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아하, 뉴스에서 본 적 있어요! 카운터 총동원령이 내려졌을 때구나.","JPN":"あ、ニュースで見ました！　カウンター総動員令が出た時ですね。","ENG":"Oh, I remember. That’s when they mobilized all Counters.","TWN":"喔喔！我有看過新聞！就是制裁者總動員那次嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤… 그때만 해도 제가 이렇게 마녀가 될 줄은 꿈에도 상상 못했는데.","JPN":"へへ……あの時は私が魔女になるなんて夢にも思わなかったな。","ENG":"Hehe. I never knew I was going to be a witch back then.","TWN":"嘿嘿…那時候我連做夢都沒想過我會變成魔女呢？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아직 견습이지만.","JPN":"まだ見習いだがな。","ENG":"You’re still in training, though.","TWN":"還在實習階段啦。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…읏, 너무해! 라우라.","JPN":"うう、ひどい、ラウラ！","ENG":"Aww, don’t ruin the mood, Laura.","TWN":"…蘿拉你很討厭欸！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…아무튼 이걸로 직원 복지는 이걸로 충분하지? 내일부터는 다시 마법 훈련 시작이야.","JPN":"……とにかく、これで福利厚生は十分だろう？\\n明日からはまた魔法訓練が待ってるからな。","ENG":"Anyway, this was a nice employee outing, right? We will start training again tomorrow.","TWN":"…總之這就是你們的員工福利，玩夠了吧？明天要繼續訓練魔法知道嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…자, 잠깐만! 아직, 아직 아니야!","JPN":"……ま、待って！　まだ、まだなの！","ENG":"W-wait! Not just yet!","TWN":"…先等一下！還沒玩夠啦！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아직 기념품을 못 샀단 말이야!","JPN":"まだお土産を買ってないよ！","ENG":"I have to buy a souvenir!","TWN":"人家還沒買紀念品欸！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"여기 귀신의 집에서만 살 수 있는 1인 1개 한정 초콜릿 케이크가 있거든!","JPN":"ここのお化け屋敷でしか買えない、1人1個までの限定チョコレートケーキがあるの！","ENG":"They sell limited edition cakes at the haunted house, only one per person!","TWN":"鬼屋有賣一人限購一份的巧克力蛋糕!"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그것도 민트 맛!","JPN":"しかも、ミント味！","ENG":"They even have mint-flavored cakes!","TWN":"而且還是薄荷口味欸！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"또 시작이네. 늦기 전에 얼른 갔다 와.","JPN":"また始まった。さっさと行ってこい。","ENG":"Here you go again. Okay, come back before it’s too late.","TWN":"又來了，要買就趕快。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어서오세요. 오싹오싹한~ 호박 귀신의 집입니다.","JPN":"いらっしゃいませ。ゾクゾクかぼちゃのお化け屋敷でーす。","ENG":"Welcome to the Creepy Pumpkin Ghost’s House!","TWN":"歡迎光臨，這裡是恐怖喔～南瓜鬼屋。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저... 오싹오싹 호박 초콜릿 케이크 하나 주세요.","JPN":"あの……ゾクゾクかぼちゃのチョコレートケーキを一つください。","ENG":"Um... can I have a Creepy Pumpkin Chocolate Cake?","TWN":"我…想要一個恐怖喔南瓜巧克力蛋糕。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"민트 맛으로!","JPN":"ミント味で！","ENG":"Mint flavor, please!","TWN":"我要薄荷口味的！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민트 맛이요?","JPN":"ミント味ですね。","ENG":"Oh, you want mint?","TWN":"薄荷口味嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어디보자…….","JPN":"……ええと。","ENG":"Let’s see...","TWN":"稍等一下喔……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아!","JPN":"あ！","ENG":"Oh!","TWN":"哇！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민트 맛은 딱 두 개 남았네요. 손님, 운이 좋으세요.","JPN":"ミント味は残り2つでした。お客さん、運がいいですね。","ENG":"We have only two mint cakes left. You’re lucky.","TWN":"薄荷口味只剩二個，你很幸運喔。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"됐어! 드디어 샀다!","JPN":"やった！　ついに買えたあ！","ENG":"Yes! I’m so lucky!","TWN":"耶！終於買到了！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어라? 그런데 두 개요?","JPN":"あれ？　2つって言いましたか？","ENG":"Wait... You have two left?","TWN":"不過剩下二個嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"네. 혹시 일행 분 있으세요? 1인 1구매가 원칙이긴 한데.","JPN":"はい。お連れの方はいらっしゃいませんか？　原則1人1個までなんですが……","ENG":"Yes. Did you bring a friend with you? We only sell one per person.","TWN":"是的，請問你是和朋友一起來的嗎？原則上是一人限購一個。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"사실, 구매를 안 하신 분이 구매하셔서 양도하는 건 상관 없거든요.","JPN":"まだご購入されていない方が買って、他の方にお譲りするのは構いませんので。","ENG":"You can ask your friend to buy it for you if you want them both.","TWN":"不過要是請朋友代購也是可以的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아하! 그렇구나!","JPN":"なるほど！　そうなんですね！","ENG":"Oh, bummer!","TWN":"喔！是喔！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에이, 아깝다! 이럴 줄 알았으면 잉그리드랑 같이 올 걸.","JPN":"あ～あ、もったいない！　イングリッドと一緒に来ればよかったなあ。","ENG":"I should have brought Ingrid with me.","TWN":"真可惜！早知道就把英格麗一起帶來。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"괜찮으시면, 일행 분 오실 때까지 맡아 둘까요?","JPN":"もしよろしければ、お連れの方がいらっしゃるまで取り置きもできますよ。","ENG":"Or do you want me to keep it for you until you bring your friend here?","TWN":"還是我先幫你留著，你去找你的朋友過來呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 그래도 돼요?","JPN":"えっ、いいんですか？","ENG":"You would do that for me?","TWN":"真的嗎？可以嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그럼요!","JPN":"もちろんです！","ENG":"Sure!","TWN":"當然沒問題。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"무, 물론... 빨리 팔아버리고 쉬고 싶어서 그런 건 절대 아니고요. 아하하.","JPN":"け、決して早く売り切っちゃって休みたいわけではないですから、あはは。","ENG":"O-of course it’s not that I want to sell them all at once and take a break... Haha.","TWN":"雖然…我個人是很想趕快賣光回家休息啦，不過顧客至上。哈哈哈。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"자, 잠깐만요! 지금 돌아가서 잉그리드한테 부탁하려고 하면…….","JPN":"で、でも今から戻ってイングリッドに頼んでも……","ENG":"But if I go back now and ask Ingrid to help me, Laura will say...","TWN":"那你等我！我現在回去拜託英格麗……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"무슨 헛소리야, 그깟 케이크 하나 샀으면 됐지, 뭘 또 산다는 거야?","JPN":"何を言ってるんだ？　そんなケーキ、1個あればもう十分だろう。","ENG":"What? You already have a cake, why would you need another?","TWN":"買一個就好，為什麼要買二個？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"안 돼. 절대 안 돼.","JPN":"絶対ダメだ。帰るぞ。","ENG":"No. You can’t buy another cake.","TWN":"不行！只能買一個。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…이럴 게 뻔하잖아.","JPN":"……って言われるに違いない。","ENG":"That’s exactly what she will say.","TWN":"…蘿拉一定會不准我買的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"여기 오싹오싹 호박 초콜릿 케이크 하나 주시겠어요?","JPN":"あの、ゾクゾクかぼちゃのチョコレートケーキを１つください。","ENG":"Hello, I would like a Creepy Pumpkin Chocolate cake, please.","TWN":"你好，我想要一個恐怖喔南瓜巧克力蛋糕。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으앗! 이러다 다 팔리겠어!! 어떡하지!?","JPN":"うわっ！　このままじゃすぐ売り切れちゃう！　どうしよう。","ENG":"Oh no! They might be sold out! What do I do?","TWN":"糟糕！不趕快買的話會被賣掉的！！怎麼辦！？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…아! 그래!","JPN":"……あっ、そうだ！","ENG":"Oh, I know!","TWN":"…好！就這樣！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 금방 친구 데리고 올게요!","JPN":"す、すぐ友だちを連れてきますから！","ENG":"L-let me go get my friend!","TWN":"我…我立刻去把人帶來！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잠시만 기다려 주세요!","JPN":"ちょっと待っててください！","ENG":"Please wait for me!","TWN":"你等我！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드가 말했었지.","JPN":"イングリッドが言ってたよね。","ENG":"Ingrid told me once.","TWN":"英格麗說過，"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"솔라코덱스를 펼치면, 어쩐지 키도 커지고 분위기도 어른스러워진다고.","JPN":"ソーラーコーデックスを開けば、なんだか背が伸びて雰囲気まで大人っぽくなるって。","ENG":"That I look taller and more mature when I use the Solar Codex.","TWN":"展開太陽法典後，不只會長高，還會變得像大人一樣。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런데 이런 일로 솔라코덱스를 펼쳐도 되는 걸까? 레일리가 잔소리할 게 뻔한데…….","JPN":"でもこんなことでソーラーコーデックスを開いてもいいのかな？　レイリーに怒られるよね……","ENG":"But is it okay to use the Solar Codex for this? Rayleigh will nag at me for sure.","TWN":"可是可以因為這種事展開太陽法典嗎？瑞利肯定會罵人的吧……"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그치만 한 개밖에 안 남았는 걸.","JPN":"で、でも最後の1個だし。","ENG":"B-but... they only have one cake left.","TWN":"可是…就只剩下一個欸！"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……에라 모르겠다. 허락보다는 용서가 쉽다는 말도 있잖아?","JPN":"……ええい、悩んでる時間なんてない！　許可を求めるより許しを請う方が簡単とも言うじゃない。","ENG":"Oh, heck. Better to ask for forgiveness than wait for permission.","TWN":"……不管了啦，先斬後奏比較容易吧？"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"뒷일은 어떻게든 되겠지!","JPN":"なるようになる！","ENG":"I’ll figure it out somehow!","TWN":"做完再想辦法乞求原諒吧！"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"솔라 코덱스, 세트 온!","JPN":"ソーラーコーデックス、セット・オン！","ENG":"Solar Codex set on!","TWN":"太陽法典，展開！"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_CONTRACT_PAPER"},{"id":"L42_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"하암... 유나 무슨 일이야? 오늘은 훈련 쉬는 날이라고 하지 않았나?","JPN":"ふあ～どうした。今日の訓練は休みって言ってなかったか？","ENG":"*Yawn* What’s going on, Yuna? Didn’t you say there was no training today?","TWN":"哈啊…尤娜，有什麼事嗎？今天不是休息不用訓練嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAMP_FIRE_LOOP"},{"id":"L45_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아하, 아하하… 레일리 그게……","JPN":"あ、あはは……レイリー、それがね……","ENG":"Haha... Rayleigh... You see...","TWN":"哈哈，哈哈哈…瑞利…那個…"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"유나, 이 녀석!! 겨우 이런 일로 솔라코덱스를 펼쳐!?","JPN":"お前！！　そんな理由でソーラーコーデックスを開いたのか！？","ENG":"Yuna, you used the Solar Codex to get more cakes?!","TWN":"尤娜，你這傢伙！！竟然因為這種事就展開太陽法典！？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"솔라코덱스가 얼마나 위험한 물건인 줄 알아??","JPN":"ソーラーコーデックスがどれだけ危険なものか、知ってるよな！？","ENG":"Do you have any idea how dangerous that is?","TWN":"你知道太陽法典有多危險嗎？？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"제어 유닛인 이 몸의 보조가 없었으면, 지금쯤 넌 벌써 통구이가 되어 있을 거다!!","JPN":"制御ユニットである俺がいなかったら、今頃お前は丸焦げだぞ！！","ENG":"If I wasn’t here to serve as a control unit, you would have been roasted alive!","TWN":"要不是有我這個法典控制者的輔助，你早就被烤焦了！！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"고작 초콜릿 하나 더 사려고 했다가 말이야!","JPN":"たかがチョコレートケーキを追加で買おうとして！","ENG":"For a chocolate cake!","TWN":"竟然只是因為想再買一個巧克力蛋糕！！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"그, 그치만… 이건 평범한 초콜릿이랑은 다른 걸?","JPN":"で、でも……これはただのチョコとは違うよ？","ENG":"B-but this is no ordinary chocolate cake.","TWN":"可，可是…這不是普通的巧克力蛋糕。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"할로윈 한정 오싹오싹 호박 초콜릿 케이크… 그것도 민트 맛이라고!","JPN":"ハロウィン限定のゾクゾクかぼちゃのチョコケーキ……しかもね、ミント味だよ！","ENG":"It’s a Creepy Pumpkin Chocolate Cake, only sold during the Halloween... Plus, it’s mint!","TWN":"是萬聖節限定的恐怖喔南瓜巧克力蛋糕…而且還是薄荷口味的！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아, 그래! 집에 돌아가면 레일리도 한 입 줄게!","JPN":"あ、そうだ！　帰ったらレイリーにも一口あげる！！","ENG":"Oh, I will let you have a bite when we get home, Rayleigh!","TWN":"那不然！回去後我分你一口！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아, 아니면... 두 입 정도?","JPN":"それとも……二口食べる？","ENG":"O-or maybe... a couple of bites?","TWN":"還，還是…二口？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"역대 계승자 중에서 이런 멍청한 이유로 솔라코덱스를 펼친 녀석은 너밖에 없을 거다!","JPN":"歴代継承者の中でこんなに馬鹿馬鹿しい理由でソーラーコーデックスを開いたのは\\nお前だけだぞ！","ENG":"This is the stupidest reason for using the Solar Codex I’ve ever heard of!","TWN":"在歷代的繼承人當中，只有你是因為這個愚蠢的理由而展開太陽法典！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"메이 녀석. 용케도 이런 말썽쟁이를 후계자로 지명했군.","JPN":"メイの奴、よくもこんなおてんばを後継者に選んだな。","ENG":"I can’t believe May chose such a troublemaker as her successor.","TWN":"梅伊竟然找這種腦袋不靈光的傢伙來當繼承人。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"우으… 그치만…….","JPN":"うう……でも……","ENG":"But... but...","TWN":"呃呃…可是我……"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"으휴, 됐다, 됐어. 이미 벌어진 일을 어쩌겠어.","JPN":"ああ、まったく。もういいよ、仕方ない。","ENG":"Gah, forget it. What’s done is done.","TWN":"算了算了，開都開了能怎麼辦？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"엇! 그럼 용서해주는 거야?","JPN":"えっ、許してくれるの？","ENG":"Oh! Then you’re forgiving me?","TWN":"那你可以原諒我嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"그래. 다음부터는 조심하라고.","JPN":"ああ、次からは気をつけろよ。","ENG":"Yes. And be careful next time.","TWN":"嗯嗯，下次注意一點。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"우와! 레일리 정말 고마워! 넌 최고의 파트너야!!","JPN":"わあ！　本当にありがとう！　レイリーは最高の相棒だよ！！","ENG":"Thank you, Rayleigh! You’re the best partner ever!","TWN":"哇！謝謝瑞利！！你是最棒的夥伴！！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"…에잇! 달라붙지 마! 그러다 데인다고!","JPN":"……よせ！　べたべたするな！　火傷するぞ！","ENG":"Stay away! You’ll get burned!","TWN":"…走開啦！不要靠我那麼近！會燙傷啦！"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"어머나, 저 아이... 꽤 귀엽잖아?","JPN":"あら、あの子……なかなか可愛いじゃない。","ENG":"Oh, that girl... She’s pretty cute.","TWN":"哇，那女孩…好可愛喔。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STALKER_COUNTERCASE_NULL","text":{"KOREA":"싹이 보여, 이런 곳에서 숨은 원석을 발견할 줄이야. 운이 좋네.","JPN":"見どころがあるわ。こんなところで原石に出会えるとは、ついてるわね。","ENG":"I see her potential. I didn’t expect to find a hidden diamond here. What a lucky day.","TWN":"沒想到會在這種地方發現原石，真幸運。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAYLEIGH_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"안녕하세요…….","JPN":"ただいま……","ENG":"I’m back...","TWN":"大家好……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐야, 대체 지금 시간이 몇 시야?","JPN":"おい、今何時だと思っているんだ？","ENG":"Huh? What time do you think it is?","TWN":"好什麼好，你知道現在幾點了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"미안…….","JPN":"ごめん……","ENG":"I’m sorry...","TWN":"對不……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"잠깐만 라우라. 유나 표정이 안 좋은데?","JPN":"待って、ラウラ。ユナの様子がおかしいわ。","ENG":"Wait, Laura. Something’s wrong with Yuna.","TWN":"蘿拉，你先別急著罵人，尤娜的表情好像不太對？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"…오늘 길에 무슨 일 있었니, 유나야?","JPN":"……ユナ、帰りに何かあったの？","ENG":"Something happened on your way back, Yuna?","TWN":"…發生什麼事了嗎，尤娜？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"我……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"…뭐? 그러니까 누군가 유나 너를 스토킹 하는 것 같다고?","JPN":"……え？　ストーカーされてるかもしれない？","ENG":"What? You think someone is stalking you?","TWN":"…你怎樣？該不會是有人跟蹤你吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"... Yes.","TWN":"……嗯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"에이, 그걸 그렇게 심각하게 생각할 필요가 있어?","JPN":"なんだ、そんなに深刻に考える必要ある？","ENG":"Come on. Why so serious?","TWN":"喔～小事啦，不用太擔心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"애초에 강도든, 스토커든 알게 뭐야?","JPN":"そもそも強盗だろうがストーカーだろうが、関係なくない？","ENG":"Who cares if it’s a robber, or a stalker?","TWN":"管他是強盜還是跟蹤狂，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"승부를 걸어오는 거라면 힘으로 찍어 누르면 그만이잖아?","JPN":"喧嘩を売られたら、力でねじ伏せてやればいいじゃない。","ENG":"If they challenge you, you can just kick their butts.","TWN":"只要是來找麻煩的，就用拳頭給他好看就好啦！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"헤헷, 무서우면 언제든 말만 하라고. 대신 승부해줄 테니까.","JPN":"ヘヘッ、怖かったらいつでも言ってね。代わりに勝負してあげるから。","ENG":"Hehe, just tell me when you need my help. I’ll be there for you.","TWN":"嘿嘿，你會怕的話隨時跟我說，我替你教訓他。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…하, 하하. 그래, 고마워.","JPN":"……は、はは。わかった、ありがとう。","ENG":"Oh... haha. Thank you.","TWN":"…哈，哈哈。好喔，謝謝。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"라우라는 어떻게 생각해?","JPN":"ラウラはどう思う？","ENG":"What do you think, Laura?","TWN":"那蘿拉覺得呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…흥, 자업자득이지, 뭐.","JPN":"……ふん。自業自得だろ。","ENG":"I’d say she brought it on herself.","TWN":"…哼，你活該。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러게 누가 그런 멍청한 짓을 하래? 마녀가 돼서 남들 눈에 띄면 어쩌자는 거야?","JPN":"毎度バカなことをやってるからだろう。魔女のくせに目立ってどうするって言うんだ。","ENG":"It was a stupid thing to do. A witch shouldn’t draw attention to herself!","TWN":"誰叫你要做那種愚蠢的事？要是被人發現你是魔女，你打算怎麼辦？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머, 우리가 떳떳하게 할 말은 아닌 거 같은데, 라우라?","JPN":"あら、私たちが堂々と言えたことじゃないわよ、ラウラ。","ENG":"Oh, we’re not really in any position to say that, Laura.","TWN":"哎呀，蘿拉你不要這麼兇啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어쨌든 다 같이 생각해보자. 생각보다 심각한 일일 지도 모르니까.","JPN":"とにかくみんなで考えてみましょう。殊の外深刻な事態かもしれないわ。","ENG":"Anyway, let’s discuss this together. It could be a serious situation.","TWN":"總之大家一起想想辦法吧。這件事說不定比想像中還要嚴重呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"시, 심각한 일이요?","JPN":"し、深刻な事態？","ENG":"S-serious?","TWN":"很，很嚴重嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"當然。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네가 솔라코덱스를 사용하는 걸 보고, 그걸 훔치려는 녀석일지도 모르지.","JPN":"ソーラーコーデックスを使う汝を見て、それを盗もうとする愚か者かもしれん。","ENG":"Maybe this person saw you using the Solar Codex, and wants to steal it.","TWN":"說不定那個人是看到你使用太陽法典，就想來把它偷走。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"솔라코덱스를… 훔쳐?","JPN":"ソーラーコーデックスを……盗む？","ENG":"Steal my Solar Codex?","TWN":"偷走…太陽法典？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그치만 솔라코덱스에 깃든 힘은 태양의 대마녀만 다룰 수 있잖아.","JPN":"で、でもソーラーコーデックスに宿る力は、太陽の大魔女じゃないと制御できないでしょ？","ENG":"B-but only the Great Witch of the Sun can use the Solar Codex, right?","TWN":"可，可是不是只有大魔女可以控制太陽法典的力量嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"소유자를 불태우는 책을 훔쳐서 뭐하게?","JPN":"使い手まで燃やしてしまう本を盗んでどうするの？","ENG":"Who would want a book that burns anyone who holds it?","TWN":"那個人沒事偷走一本會把自己燒焦的書要幹嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당연히 훔치려는 쪽이 우리만 알고 있는 자세한 사정 따위를 알고 있을 리가 없지.","JPN":"それは妾たちだけが知っていることで、盗もうとしてるやつが知らなくても当然だろう。","ENG":"You can’t expect a thief to know such details.","TWN":"那個想偷的人怎麼會知道這些事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"세상에는 아티팩트만 보면, 눈 돌아가는 트레져 헌터 같은 녀석들도 잔뜩 있다고.","JPN":"世の中にはアーティファクトに目が眩んだトレジャーハンターみたいな連中が\\nいっぱいいるんだ。","ENG":"There are a lot of treasure hunters who just go crazy when they see an Artifact.","TWN":"只要有人造神器，就會有許多虎視眈眈的人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"어쩌면 널 따라다니는 녀석은 그 책을 키가 커지는 아티팩트쯤으로 착각하고 있을지도 몰라.","JPN":"もしかしたら、汝のストーカーはその本を身長が伸びる程度のアーティファクトだと\\n勘違いしているかもしれない。","ENG":"Maybe this stalker thinks your book is an Artifact that makes you taller.","TWN":"說不定那個跟蹤你的人以為那本書是可以長高的人造神器。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…키, 키가 커지는 아티팩트?","JPN":"……し、身長が伸びるアーティファクト？","ENG":"An Artifact that makes you taller?","TWN":"長高的…人造神器？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"혹시 또 모르지. 계승자인 너와 솔라코덱스를 떼어놓는 것 자체가 목적일지도.","JPN":"もしくは、継承者である汝とソーラーコーデックスを引き離すことが目的かもしれない。","ENG":"Who knows? Maybe they want to separate you from the Solar Codex.","TWN":"誰知道？說不定也有可能是要把身為繼承人的你和太陽法典分開。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…그, 그런 걸까?","JPN":"……そ、そうなのかな？","ENG":"D-do you think so?","TWN":"…真，真的假的？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…엇?!","JPN":"……えっ！？","ENG":"Huh?","TWN":"…嗯？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"…어라? 아직 오픈 시간 조금 남지 않았어?","JPN":"……あれ？　開店まではまだ時間があるよね。","ENG":"Eh? I thought we had some time left before the shop opened.","TWN":"…奇怪？又還沒到開店時間？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……서 설마, 그 스토커가?","JPN":"……ま、まさか、ストーカー？","ENG":"C-could it be the stalker?","TWN":"…難…難道是那個跟蹤狂？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"…어머, 뒷모습이 보여서 따라왔는데.","JPN":"……あら、後ろ姿が見えたので付いてきたのですが。","ENG":"Oh, I saw you from behind and followed you.","TWN":"…哈囉，我看到你的背影所以就跟上來。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어쩜, 다시 봐도 동생 분… 언니랑 정말 닮으셨네요.","JPN":"妹さんだったのですか。お姉さんにそっくりですね。","ENG":"You do look like your sister.","TWN":"你…和姊姊長得很像呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…네? 어, 어 언니요?","JPN":"……はい？　お、お姉さん？","ENG":"Huh? M-my sister?","TWN":"…什麼？姊姊？"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아하, 그게…… 얼마전에 우연히 놀이 공원에서 언니 분을 보고 잠재성을 느꼈거든요.","JPN":"ええ、それが……数日前、遊園地でお姉さんを偶然見かけまして、\\nポテンシャルを感じたのです。","ENG":"Oh, you see... I saw your sister at the amusement park, and I saw potential in her.","TWN":"哈哈，是這樣的……我之前在遊樂園看到你姊姊，覺得她很有潛力。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"탄탄한 복근에… 늘씬한 몸매… 그리고 과감한 복장도 소화할 수 있는 능숙한 분위기까지!","JPN":"逞しい腹筋……すらりとした体形……そして大胆な衣装も着こなせる色っぽい雰囲気！","ENG":"Her tight abs, slender figure... and a mature allure that will go well with a bold outfit!","TWN":"她不只有馬甲線…身材又高挑…還可以駕馭任何大膽的服裝！"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"저와 함께라면 분명히 멋진 아이돌이 되실 수 있을 거예요.","JPN":"私と一緒なら、きっとトップアイドルになれます。","ENG":"I’m sure she will become a superstar if she works with me.","TWN":"我可以讓她成為大明星喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 아하하. 그런데 전 언니가…….","JPN":"あ、あはは。ところで私にお姉さんは……","ENG":"Hahaha... But I don’t have a—","TWN":"哈，哈哈。可是我姊姊……"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"…아! 이런, 제 소개가 늦었네요. 저는 이런 사람입니다.","JPN":"……あ！　申し遅れました。私、こういう者です。","ENG":"Oh, I haven’t introduced myself yet. Here is my card.","TWN":"…對了！差點忘了自我介紹，這是我的名片。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_UI_CONTRACT_PAPER"},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…하트 베리의 최이나 매니저 님?","JPN":"……ハートベリーのマネージャー、ハラジマ・メグミさん？","ENG":"Choi Ina... The manager of HRT Berry?","TWN":"你是…愛心莓果的經紀人崔理娜？"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어라?! 하트 베리라면 그……!!","JPN":"ええ！？　ハートベリーって、あの……！！","ENG":"Huh?! HRT Berry? You mean the...","TWN":"真的假的？！愛心莓果不就是……！！"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"네, 맞아요! 언니 분께 그 명함 꼭 좀 전해 주시겠어요?","JPN":"はい、そうです！　私の名刺、お姉さんにぜひ渡していただけますか？","ENG":"Yes! Could you please pass my card on to your sister?","TWN":"沒錯！請你一定要將我的名片轉交給姊姊喔！"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아, 그리고 커피는 아이스커피로 한 잔 부탁 드릴게요.","JPN":"あ、注文はアイスコーヒーでお願いします。","ENG":"Oh, and I would like an iced coffee, please.","TWN":"另外再麻煩給我一杯冰美式。"},"stage":{"bg":"CAFE_STREGA","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이야~ 이런 걸 길거리 캐스팅이라고 하나?","JPN":"わあ！　こういうのを街中スカウトっていうんでしょ？","ENG":"Wow, you were scouted on the street?","TWN":"哇～這是所謂的星探嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"유나, 대단한데?","JPN":"ユナ、すごいじゃない！","ENG":"Yuna, you’re amazing!","TWN":"尤娜，厲害喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에헷, 엄밀히 말하면 내가 캐스팅된 것도 아닌데 뭘…….","JPN":"えへへ、正確には私へのスカウトじゃないけどね……","ENG":"Hehe. But it’s not me that she wanted to scout...","TWN":"哈哈，嚴格來說，星探想找的人不是我吧……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후후, 그래도 본판이 귀여우니까, 솔라코덱스의 힘이 더 돋보이는 거 아닐까?","JPN":"ふふ。きっと素材が可愛いからソーラーコーデックスの力も活かせるんじゃない？","ENG":"Oh, you’re pretty yourself. The Solar Codex only helps you stand out.","TWN":"呵呵，至少你本人是可愛的，再加上太陽法典的加持？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에이, 에블린 언니도 참… 너, 너무 비행기 태우지 마세요.","JPN":"もう、エヴリン姉さんったら……誉めても何も出ませんよ。","ENG":"Evelyn, don’t make me blush.","TWN":"伊芙琳姊姊討厭…一直灌我迷湯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……흥, 재미없어.","JPN":"……ふん、くだらん。","ENG":"Hmpf, it’s not fun at all.","TWN":"……哼，無聊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"별 것도 아닌 일에 우쭐하긴. 너 때문에 괜히 시간만 날렸잖아.","JPN":"大したことでもないのに舞い上がるとは。汝のせいで開店準備が遅れたぞ。","ENG":"Don’t get all snippy. So, it was all a waste of time after all.","TWN":"有什麼了不起的，浪費大家的時間。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤, 미안 미안.","JPN":"へへ、ごめんごめん。","ENG":"Hehe, I’m sorry.","TWN":"嘿嘿，抱歉抱歉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머나, 우리 라우라가 왜 이렇게 심통이 났을까?","JPN":"あら、どうしてご機嫌斜めなのかしら、ラウラ？","ENG":"Aww, Laura. Why are you being so mean?","TWN":"哎呀呀，蘿拉幹嘛不開心啊？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"시끄러, 약장수.","JPN":"うるさい、薬屋。","ENG":"Shut it, Potion Peddler.","TWN":"你好煩，少廢話。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};